<?php
namespace App\Domain\Wallet\Data;
final class GoldTransactionEntry { private $values; public function __construct($id,$characterId,$type,$amount,$before,$after,$reason,$description,$referenceType,$referenceId,$createdAt){$this->values=compact('id','characterId','type','amount','before','after','reason','description','referenceType','referenceId','createdAt');} public function transactionId(){return (int)$this->values['id'];} public function characterId(){return (int)$this->values['characterId'];} public function transactionType(){return $this->values['type'];} public function amount(){return (int)$this->values['amount'];} public function balanceBefore(){return (int)$this->values['before'];} public function balanceAfter(){return (int)$this->values['after'];} public function reasonCode(){return $this->values['reason'];} public function description(){return $this->values['description'];} public function referenceType(){return $this->values['referenceType'];} public function referenceId(){return $this->values['referenceId']===null?null:(int)$this->values['referenceId'];} public function createdAt(){return $this->values['createdAt'];} }
